import axios from 'axios';
import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const PortfolioList = () => {
    const [works, setWorks] = useState([]); // Список работ
    const [categories, setCategories] = useState([]); // Список категорий
    const [selectedCategory, setSelectedCategory] = useState(''); // Фильтр по категории
    const [currentPage, setCurrentPage] = useState(1); // Текущая страница
    const [nextPage, setNextPage] = useState(null); // Ссылка на следующую страницу
    const [prevPage, setPrevPage] = useState(null); // Ссылка на предыдущую страницу
    const [isLoading, setIsLoading] = useState(true); // Флаг загрузки

    // Загрузка списка работ
    useEffect(() => {
        fetchWorks(currentPage);
    }, [currentPage, selectedCategory]);

    const fetchWorks = async (page = 1) => {
        setIsLoading(true);
        try {
            const queryParam = selectedCategory ? `&category=${selectedCategory}` : '';
            const response = await axios.get(
                `${process.env.REACT_APP_API_URL}/api/portfolio/?page=${page}${queryParam}`
            );

            setWorks(response.data.results || []); // Загружаем работы
            setNextPage(response.data.next); // Ссылка на следующую страницу
            setPrevPage(response.data.previous); // Ссылка на предыдущую страницу
        } catch (error) {
            console.error('Error fetching portfolio works:', error);
            setWorks([]);
        } finally {
            setIsLoading(false);
        }
    };

    // Загрузка списка категорий
    useEffect(() => {
        const fetchCategories = async () => {
            try {
                const response = await axios.get(`${process.env.REACT_APP_API_URL}/api/portfolio/categories/`);
                setCategories(response.data || []); // Загружаем категории
            } catch (error) {
                console.error('Error fetching portfolio categories:', error);
                setCategories([]);
            }
        };

        fetchCategories();
    }, []);

    return (
        <div>
            <h1>Portfolio</h1>

            {/* Фильтр по категориям */}
            <label>Filter by Category: </label>
            <select
                value={selectedCategory}
                onChange={(e) => {
                    setSelectedCategory(e.target.value);
                    setCurrentPage(1); // Сбрасываем на первую страницу при смене категории
                }}
            >
                <option value="">All</option>
                {categories.map((category) => (
                    <option key={category.id} value={category.id}>
                        {category.name}
                    </option>
                ))}
            </select>

            {/* Список работ */}
            {isLoading ? (
                <p>Loading...</p>
            ) : works.length > 0 ? (
                <div>
                    {works.map((work) => (
                        <div key={work.id} style={{ margin: '20px 0', border: '1px solid #ddd', padding: '10px' }}>
                            <h3>{work.name}</h3>
                            <p><strong>Type:</strong> {work.type}</p>
                            <p><strong>Description:</strong> {work.description}</p>
                            {work.image && (
                                <img
                                    src={`${process.env.REACT_APP_API_URL}${work.image}`}
                                    alt={work.name}
                                    width="200"
                                />
                            )}
                            <Link to={`/portfolio/${work.id}`}>View Details</Link>
                        </div>
                    ))}
                </div>
            ) : (
                <p>No works found.</p>
            )}

            {/* Пагинация */}
            <div style={{ marginTop: '20px' }}>
                {prevPage && (
                    <button onClick={() => setCurrentPage((prev) => prev - 1)}>Previous</button>
                )}
                <span style={{ margin: '0 10px' }}>Page {currentPage}</span>
                {nextPage && (
                    <button onClick={() => setCurrentPage((prev) => prev + 1)}>Next</button>
                )}
            </div>
        </div>
    );
};

export default PortfolioList;
